import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface City {
  name: string;
  localTime: string;
  dateDifference: string;
}

interface TimezoneClocksData {
  cities: City[];
}

export default function Widget() {
  const timezoneClocksData = response.data.data as TimezoneClocksData;
  const { theme, primaryColor, accentColor } = response.data.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 400, bgcolor: theme === 'light' ? '#FFFFFF' : '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
            World Clock
          </Typography>
          {timezoneClocksData.cities.map((city) => (
            <Box key={city.name} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Typography variant="body1" sx={{ color: theme === 'light' ? '#333' : '#EEE' }}>
                {city.name}
              </Typography>
              <Typography variant="body2" sx={{ color: accentColor }}>
                {city.localTime} {city.dateDifference !== '+0' && `(Day ${city.dateDifference})`}
              </Typography>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
